INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_351','カーボン市場参加採用研究','Carbon Market Participation Adoption Research','EU-ETS・カリフォルニアキャップアンドトレード・J-クレジット等炭素市場への企業参加採用を分析した研究群。炭素価格シグナルの明確性・規制コンプライアンス動機・戦略的低炭素化意図が採用規定因として確認されている。','脱炭素政策の市場メカニズム設計と企業の気候変動戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','カーボン市場採用研究','2010','meso','adoption','regulatory_market_adoption','["Ellerman, A.D.", "Convery, F.J.", "de Perthuis, C."]','["Ellerman et al. (2010) Pricing Carbon", "Convery & Redmond (2007) EU ETS"]','炭素市場,EU-ETS,カーボンクレジット,脱炭素採用','carbon market,EU-ETS,carbon credit,decarbonization adoption'),
('inno_diff_352','補完的医療・代替医療採用研究','Complementary and Alternative Medicine Adoption Research','鍼治療・漢方・ホメオパシー・マインドフルネスなどCAM採用の規定因を分析した研究群。主流医療への不満・全体論的健康観・文化的親近性・社会的規範が採用規定因として確認されている。科学的エビデンスとの緊張関係も重要テーマとなっている。','統合医療政策と医療費適正化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','代替医療採用研究','2002','micro','adoption','holistic_health_adoption','["Ernst, E.", "Harris, P.", "Astin, J.A."]','["Astin (1998) Why patients use CAM", "Ernst (2000) CAM evidence"]','補完代替医療,CAM,鍼治療,統合医療','complementary alternative medicine,CAM,acupuncture,integrative medicine'),
('inno_diff_353','空飛ぶクルマ（eVTOL）採用の社会受容研究','Social Acceptance Research on eVTOL Air Mobility Adoption','Joby Aviation・Archer・Lilium等電動垂直離着陸機（eVTOL）への都市住民受容と採用意図を分析した研究群。騒音・安全性・価格・都市景観への影響・ヘリポートインフラが受容規定因として確認されている。','都市航空モビリティ規制政策とUAM（都市型航空交通）インフラ計画に実証的根拠を提供した。','diffusion_adoption_user','C_processes','都市航空モビリティ採用研究','2020','meso','adoption','urban_air_adoption','["Cohen, A.P.", "Shaheen, S.", "Farooq, B."]','["Cohen & Shaheen (2021) UAM adoption", "Farooq et al. (2021) eVTOL acceptance"]','eVTOL,都市航空モビリティ,UAM,空飛ぶクルマ','eVTOL,urban air mobility,UAM,flying car'),
('inno_diff_354','神経インタフェース（BCI）採用研究','Brain-Computer Interface Adoption Research','Neuralink・BrainGate・Neuropaceなどブレイン-コンピュータインタフェースの医療・健康・エンタメでの採用を分析した研究群。侵襲性不安・精神的オートノミー・データセキュリティ・認知的アイデンティティへの脅威が採用障壁として確認されている。','BCI倫理規制と神経技術産業政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','神経技術採用研究','2019','micro','adoption','cognitive_autonomy_adoption','["Nijholt, A.", "Zander, T.", "Burwell, S."]','["Nijholt (2019) Brain Art BCI", "Burwell et al. (2017) BCI ethics"]','BCI,ブレインコンピュータ,神経インタフェース,神経倫理','BCI,brain computer,neural interface,neuroethics'),
('inno_diff_355','宇宙食・宇宙農業技術採用研究','Space Food and Space Agriculture Technology Adoption Research','ISS・月面基地・火星探査を想定した閉鎖循環型農業・昆虫タンパク・培養肉等宇宙食技術の宇宙機関採用を分析した研究群。カロリー密度・廃棄物循環・心理的栄養（コンフォートフード）・栽培スペース制約が採用規定因として確認されている。','宇宙探査政策と地球上の食料安全保障技術移転に実証的根拠を提供した。','diffusion_adoption_user','C_processes','宇宙食採用研究','2017','meso','adoption','extreme_environment_adoption','["Cooper, M.", "Perchonok, M.", "Bamsey, M."]','["Perchonok & Bourland (2002) Space food", "Bamsey et al. (2012) Space agriculture"]','宇宙食,宇宙農業,閉鎖循環型栽培,ISS','space food,space agriculture,closed-loop cultivation,ISS'),
('inno_diff_356','保険テクノロジー採用の自動車保険研究（UBI）','Usage-Based Insurance Technology Adoption Research','運転行動データを活用したUBI（Usage-Based Insurance）・テレマティクス保険への消費者採用を分析した研究群。プライバシー懸念・保険料低減期待・運転行動の可視化受容が採用規定因として確認されている。','自動車保険料率規制とテレマティクスデータ利活用政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','UBI採用研究','2014','micro','adoption','data_exchange_adoption','["Bolderdijk, J.W.", "Knockaert, J.", "Steg, E.M."]','["Bolderdijk et al. (2011) UBI adoption", "Knockaert et al. (2012) Pay-as-you-drive"]','UBI,テレマティクス保険,運転行動データ,プライバシー','UBI,telematics insurance,driving behavior data,privacy'),
('inno_diff_357','サーキュラーエコノミー採用の中小企業研究','SME Research on Circular Economy Adoption','修理・再利用・再製造・サービタイゼーション等サーキュラーエコノミー戦略の中小企業採用を分析した研究群。知識不足・顧客需要不確実性・逆流物流コスト・産業エコシステム未整備が採用障壁として確認されている。','循環経済政策と中小企業支援スキーム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','サーキュラーエコノミー採用研究','2016','meso','adoption','circular_business_adoption','["Rizos, V.", "Behrens, A.", "van der Gaast, W."]','["Rizos et al. (2016) CE SME barriers", "Behrens et al. (2017) CE transition"]','サーキュラーエコノミー,循環経済,中小企業採用,再製造','circular economy,SME adoption,remanufacturing,reverse logistics'),
('inno_diff_358','プロセスマイニング採用の組織研究','Organizational Research on Process Mining Adoption','Celonis・UiPath Process Mining等プロセスマイニングツールの組織採用を分析した研究群。プロセス透明化への抵抗・データ品質・分析スキル・既存BPMとの統合が採用規定因として確認されている。','業務プロセス改善と組織変革管理の科学的根拠を提供した。','diffusion_adoption_user','C_processes','プロセスマイニング採用研究','2019','meso','adoption','process_transparency_adoption','["van der Aalst, W.M.P.", "Mans, R.", "Verbeek, H."]','["van der Aalst (2016) Process Mining", "Mans et al. (2015) Healthcare process mining"]','プロセスマイニング,Celonis,業務分析,BPM','process mining,Celonis,business process analysis,BPM'),
('inno_diff_359','高度自動化農業機械採用研究（自動運転トラクター）','Advanced Agricultural Machinery Adoption: Autonomous Tractor Research','自動運転トラクター・ロボット収穫機・播種ロボットへの農家採用を分析した研究群。農場地形・IT習熟度・農機ディーラーサポート・補助金設計が採用規定因として確認されている。農業の世代交代と採用の関係も重要テーマとなっている。','農業機械化政策と農業労働力不足対策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業機械化採用研究','2016','meso','adoption','agricultural_mechanization_adoption','["Blackmore, S.", "Pedersen, S.M.", "Fountas, S."]','["Blackmore et al. (2005) Autonomous robots agriculture", "Fountas et al. (2015) Precision farming adoption"]','自動運転トラクター,農業ロボット,農業機械化,精密農業','autonomous tractor,agricultural robot,farm mechanization,precision agriculture'),
('inno_diff_360','スマートウォーター管理採用研究','Smart Water Management Adoption Research','IoTセンサー・AIリーク検知・スマートメーター等スマート水道管理技術の水道事業者採用を分析した研究群。インフラ老朽化・技術更新コスト・組織能力・規制インセンティブが採用規定因として確認されている。水不足リスクの高い地域での急速採用も研究されている。','水道インフラ管理政策と水安全保障戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマートウォーター採用研究','2016','meso','adoption','infrastructure_modernization_adoption','["Mounce, S.R.", "Boxall, J.B.", "Laucelli, D."]','["Mounce & Boxall (2010) Leak detection", "Laucelli et al. (2016) Smart water systems"]','スマート水道,リーク検知,水管理,IoT水インフラ','smart water,leak detection,water management,IoT water infrastructure'),
('inno_diff_361','ペット向けデジタルヘルス採用研究','Digital Health for Pets Adoption Research','ペット用活動量計・遠隔獣医診療・ペット保険テクノロジーへのペットオーナー採用を分析した研究群。ペットへの愛着・獣医アドバイスへの信頼・価格感度・プライバシーが採用規定因として確認されている。','ペットケア産業のデジタル化戦略と獣医テレヘルス政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ペットテクノロジー採用研究','2017','micro','adoption','pet_care_adoption','["Shanan, A.", "Kogan, L.R.", "Quain, A."]','["Kogan & Schoenfeld-Tacher (2018) Pet owner tech", "Quain et al. (2021) Veterinary telemedicine"]','ペットデジタルヘルス,遠隔獣医,ペット活動量計,ペットテク','pet digital health,veterinary telemedicine,pet activity tracker,pet tech'),
('inno_diff_362','神経科学的消費者研究（ニューロマーケティング）ツール採用','Neuromarketing Tool Adoption Research','fMRI・EEG・アイトラッキング・ガルバニック皮膚反応などニューロマーケティングツールのマーケティングリサーチ採用を分析した研究群。コスト・倫理的懸念・解釈専門知識・通常調査との補完関係が採用規定因として確認されている。','マーケティングリサーチ方法論の高度化と消費者神経科学の応用に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ニューロマーケティング採用研究','2010','micro','adoption','measurement_complexity_adoption','["Ariely, D.", "Berns, G.S.", "Lee, N."]','["Ariely & Berns (2010) Neuromarketing", "Lee et al. (2007) Neuromarketing review"]','ニューロマーケティング,EEG,アイトラッキング,消費者神経科学','neuromarketing,EEG,eye tracking,consumer neuroscience'),
('inno_diff_363','電子投票システム採用研究','E-Voting System Adoption Research','オンライン投票・電子投票機械・ブロックチェーン投票システムへの選挙管理機関・市民採用を分析した研究群。信頼性・安全性・透明性・アクセシビリティ・選挙不正懸念が採用規定因として確認されている。エストニアの先進事例研究が特に蓄積されている。','民主的プロセスのデジタル化政策と選挙インフラ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','電子投票採用研究','2004','meso','adoption','democratic_trust_adoption','["Alvarez, R.M.", "Hall, T.E.", "Trechsel, A.H."]','["Alvarez & Hall (2004) Point Click Vote", "Trechsel & Vassil (2011) E-voting Estonia"]','電子投票,オンライン投票,選挙DX,投票セキュリティ','e-voting,online voting,election DX,voting security'),
('inno_diff_364','文化財・博物館デジタル化採用研究','Cultural Heritage and Museum Digitalization Adoption Research','3Dスキャン・VR展示・デジタルアーカイブ・AIキュレーションの博物館・美術館採用を分析した研究群。保存目的と公開目的の緊張・著作権処理コスト・デジタル予算制約・来館者体験設計が採用規定因として確認されている。','文化政策とデジタル文化遺産保存の国際標準化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','文化財デジタル化採用研究','2013','meso','adoption','cultural_preservation_adoption','["Cameron, F.", "Kenderdine, S.", "Parry, R."]','["Cameron & Kenderdine (2007) Theorizing Digital Heritage", "Parry (2007) Recoding the Museum"]','博物館デジタル化,3Dスキャン,VR展示,文化財保存','museum digitalization,3D scanning,VR exhibition,cultural heritage'),
('inno_diff_365','デジタル遺伝家系図サービス採用研究','Digital Genealogy Service Adoption Research','Ancestry.com・23andMe・MyHeritage等デジタル家系図・遺伝子家系サービスへの採用を分析した研究群。アイデンティティ欲求・プライバシー・親族関係発見への期待・遺伝的健康リスク開示意欲が採用規定因として確認されている。','遺伝子データプライバシー規制と家系調査産業の倫理設計に貢献した。','diffusion_adoption_user','C_processes','遺伝子サービス採用研究','2015','micro','adoption','identity_curiosity_adoption','["Haimes, E.W.", "Skinner, D.", "Nelson, A."]','["Haimes & Skinner (2015) Genetic genealogy", "Nelson (2016) Social Life of DNA"]','デジタル家系図,遺伝子検査,Ancestry.com,プライバシー','digital genealogy,genetic testing,Ancestry.com,privacy'),
('inno_diff_366','スマートシティ交通管理採用研究','Smart City Traffic Management System Adoption Research','適応型信号制御・V2X（車路間通信）・交通流最適化AIへの道路管理者・自動車メーカー採用を分析した研究群。標準化の不統一・データ共有ガバナンス・サイバーセキュリティが採用規定因として確認されている。','スマートシティ交通政策と自動運転インフラ整備計画に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマート交通採用研究','2017','meso','adoption','v2x_adoption','["Masello, L.", "Castignani, G.", "Dahmen, J."]','["Masello et al. (2022) V2X adoption", "Castignani et al. (2013) Smartphone driver scoring"]','スマート交通,V2X,適応信号制御,自動運転インフラ','smart traffic,V2X,adaptive signal control,autonomous driving infrastructure'),
('inno_diff_367','デジタルヘルスエコシステム採用研究（相互運用性）','Digital Health Ecosystem Adoption Research: Interoperability','FHIR・HL7・IHEプロファイル等ヘルスIT相互運用性標準の医療機関採用を分析した研究群。ベンダーロックイン・標準実装コスト・競合間データ共有抵抗が採用障壁として確認されている。','医療情報標準化政策とヘルスIT相互運用性法制度設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ヘルスIT相互運用性採用研究','2015','meso','adoption','interoperability_adoption','["Bates, D.W.", "Kashyap, V.", "Mandl, K.D."]','["Bates & Bitton (2010) Health IT interoperability", "Mandl & Kohane (2012) SMART platforms"]','FHIR,HL7,医療IT相互運用性,ヘルスデータ標準','FHIR,HL7,health IT interoperability,health data standards'),
('inno_diff_368','テレプレゼンスロボット採用研究','Telepresence Robot Adoption Research','Double Robotics・Ohmni等テレプレゼンスロボットへのオフィス・病院・学校採用を分析した研究群。遠隔参加の社会的臨場感・操作複雑性・物理的障害物への対処・プライバシーが採用規定因として確認されている。','遠隔コラボレーション政策とハイブリッドワーク設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','テレプレゼンス採用研究','2015','meso','adoption','remote_presence_adoption','["Rae, I.", "Mutlu, B.", "Khoo, M."]','["Rae et al. (2013) Telepresence robot", "Mutlu & Forlizzi (2008) Robots in organizational settings"]','テレプレゼンスロボット,遠隔臨場感,ハイブリッドワーク,遠隔参加','telepresence robot,remote presence,hybrid work,remote participation'),
('inno_diff_369','コグニティブコンピューティング採用の金融研究','Financial Industry Research on Cognitive Computing Adoption','IBM Watson・金融AIエンジン等コグニティブコンピューティングの銀行・保険・証券採用を分析した研究群。規制コンプライアンス統合・モデルリスク管理・説明可能性義務・スキル投資が採用規定因として確認されている。','金融AI規制と金融機関の技術投資意思決定に実証的根拠を提供した。','diffusion_adoption_user','C_processes','金融AI採用研究','2016','meso','adoption','financial_ai_adoption','["Davenport, T.H.", "Patil, D.J.", "Bartlett, C."]','["Davenport (2017) AI advantage", "Bartlett et al. (2020) Financial AI adoption"]','コグニティブコンピューティング,金融AI,IBM Watson,モデルリスク','cognitive computing,financial AI,IBM Watson,model risk'),
('inno_diff_370','デジタルノマド採用のリモートワークプラットフォーム研究','Digital Nomad Adoption of Remote Work Platforms','Deel・Remote・ Remotelyなどリモートワーク雇用プラットフォームとコワーキングスペースへのデジタルノマド採用を分析した研究群。税制規制・ビザ環境・コミュニティ帰属感・インターネット品質が採用規定因として確認されている。','デジタルノマドビザ政策と分散型雇用政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルノマド採用研究','2018','micro','adoption','location_independent_adoption','["Müller, A.", "Hannonen, O.", "Nash, C."]','["Müller (2016) Digital Nomad", "Nash et al. (2018) Autonomous and remote workers"]','デジタルノマド,リモートワーク,コワーキング,ノマドビザ','digital nomad,remote work,coworking,nomad visa'),
('inno_diff_371','宅配ボックス採用研究','Package Locker Adoption Research','Amazon Hub・コンビニ受け取り・自動宅配ボックスへの消費者採用を分析した研究群。再配達削減動機・セキュリティ・時間柔軟性・設置場所アクセスが採用規定因として確認されている。ラストマイル物流効率化との接続も重要テーマとなっている。','都市物流政策と集合住宅設計基準に実証的根拠を提供した。','diffusion_adoption_user','C_processes','宅配ボックス採用研究','2016','micro','adoption','delivery_convenience_adoption','["Morganti, E.", "Dablanc, L.", "Fortin, F."]','["Morganti et al. (2014) Last mile parcel delivery", "Dablanc et al. (2017) Trends parcel delivery"]','宅配ボックス,再配達削減,ラストマイル,物流DX','package locker,redelivery reduction,last mile,logistics DX'),
('inno_diff_372','パーソナライズドニュートリション採用研究','Personalized Nutrition Adoption Research','遺伝子栄養学・マイクロバイオーム分析に基づいた個別化栄養指導サービスへの採用を分析した研究群。科学的エビデンス信頼性・プライバシー・コスト・実践的実行可能性が採用規定因として確認されている。','個別化医療・予防栄養政策と食品産業のパーソナライズ化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','パーソナライズドヘルス採用研究','2018','micro','adoption','personalized_health_adoption','["Ordovas, J.M.", "Ferguson, L.R.", "Mathers, J.C."]','["Ordovas et al. (2018) Personalized nutrition", "Ferguson (2013) Nutrigenomics"]','パーソナライズド栄養,遺伝子栄養学,マイクロバイオーム,予防栄養','personalized nutrition,nutrigenomics,microbiome,preventive nutrition'),
('inno_diff_373','ジオフェンシング・位置情報サービス採用研究','Geofencing and Location-Based Service Adoption Research','位置情報ターゲティング・ジオフェンス通知・屋内測位サービスへの消費者採用を分析した研究群。利便性・プライバシー侵害懸念・バッテリー消費・通知過多が採用規定因として確認されている。','位置情報データ活用規制とロケーションマーケティング設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','位置情報サービス採用研究','2012','micro','adoption','location_privacy_adoption','["Xu, H.", "Oh, L.B.", "Teo, H.H."]','["Xu et al. (2011) Location-based services privacy", "Oh et al. (2008) LBS adoption"]','位置情報サービス,ジオフェンシング,プライバシー,ロケーションマーケティング','location-based services,geofencing,privacy,location marketing'),
('inno_diff_374','スポーツベッティングプラットフォーム採用研究','Sports Betting Platform Adoption Research','オンラインスポーツベッティング・ライブベッティングへの採用を分析した研究群。合法化政策の影響・ギャンブル依存リスク認知・オッズ情報の透明性・スポーツファンアイデンティティが採用規定因として確認されている。','スポーツベッティング規制政策とギャンブル依存予防政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ギャンブルテクノロジー採用研究','2015','micro','adoption','entertainment_risk_adoption','["Lopez-Gonzalez, H.", "Estévez, A.", "Griffiths, M.D."]','["Lopez-Gonzalez et al. (2018) Sports betting advertising", "Griffiths (2010) Online gambling"]','スポーツベッティング,オンラインギャンブル,ライブベッティング,ギャンブル依存','sports betting,online gambling,live betting,gambling addiction'),
('inno_diff_375','クライメートテック採用の投資家研究','Investor Research on Climate Tech Adoption','太陽光・風力・蓄電池・CCS・DAC等クライメートテックへのVC・PE・機関投資家採用を分析した研究群。技術リスク・政策安定性・エグジット市場・共同投資ネットワークが採用規定因として確認されている。','クライメートファイナンス政策とグリーンスタートアップエコシステム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','クライメートテック投資採用研究','2019','meso','adoption','impact_investment_adoption','["Azar, J.", "Duro, M.", "Hoepner, A."]','["Azar et al. (2021) Net zero commitment VC", "Hoepner et al. (2021) ESG investment adoption"]','クライメートテック,グリーン投資,CCS,ESG採用','climate tech,green investment,CCS,ESG adoption'),
('inno_diff_376','マイクロ保険採用研究（途上国）','Micro-Insurance Adoption Research in Developing Countries','天候指数保険・家畜保険・農業マイクロ保険への途上国農家採用を分析した研究群。ベーシストリスク（指数と実損の乖離）・保険リテラシー・信頼・支払い能力が採用規定因として確認されている。RCT研究が特に蓄積されている。','農業リスク管理政策と国際農業保険制度設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','マイクロ保険採用研究','2008','micro','adoption','trust_insurance_adoption','["Cole, S.", "Barnwal, P.", "Giné, X."]','["Cole et al. (2013) Weather insurance India", "Giné & Yang (2009) Microinsurance takeup"]','マイクロ保険,天候指数保険,途上国農業保険,ベーシストリスク','micro-insurance,weather index insurance,developing country agricultural insurance,basis risk'),
('inno_diff_377','デジタル地図・GISツール採用研究','Digital Mapping and GIS Tool Adoption Research','Google Maps・QGIS・ArcGIS・OSMへの計画担当者・研究者・市民採用を分析した研究群。GISリテラシー・データ入手性・オープンデータ政策・プロプライエタリvsオープンのトレードオフが採用規定因として確認されている。','空間データ基盤政策とデジタル国土管理に実証的根拠を提供した。','diffusion_adoption_user','C_processes','GIS採用研究','2005','meso','adoption','spatial_literacy_adoption','["Longley, P.A.", "Goodchild, M.F.", "Maguire, D.J."]','["Longley et al. (2011) Geographic Information Science", "Goodchild (2007) Citizens as sensors"]','GIS,デジタル地図,空間データ,オープンGIS','GIS,digital mapping,spatial data,open GIS'),
('inno_diff_378','在宅ケアロボット採用の家族介護者研究','Family Caregiver Research on Home Care Robot Adoption','LOVOT・Pepper・介護補助外骨格ロボット等在宅介護ロボットへの家族介護者採用を分析した研究群。介護負担軽減への期待・ロボットへの家族員委託への罪悪感・コスト・設置スペースが採用規定因として確認されている。','在宅介護政策と高齢社会ロボティクス製品設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','介護ロボット採用研究','2017','micro','adoption','caregiver_burden_adoption','["Cesta, A.", "Cortellessa, G.", "Tiberio, L."]','["Cesta et al. (2011) Enabling remote care", "Tiberio et al. (2012) Acceptability eldercare robots"]','在宅ケアロボット,介護ロボット,外骨格,家族介護者','home care robot,care robot,exoskeleton,family caregiver'),
('inno_diff_379','デジタルリハビリテーション採用研究','Digital Rehabilitation Adoption Research','VRリハビリ・ゲーミフィケーションリハビリ・在宅リハビリアプリへの患者・理学療法士採用を分析した研究群。モチベーション維持・安全性・セラピスト監督の必要性・保険適用が採用規定因として確認されている。','リハビリ医療のデジタル化政策と遠隔リハビリ制度設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルリハビリ採用研究','2016','micro','adoption','rehabilitation_engagement_adoption','["Levin, M.F.", "Weiss, P.L.", "Keshner, E.A."]','["Levin et al. (2015) Emergence of virtual reality in rehabilitation", "Weiss et al. (2006) VR in rehab"]','デジタルリハビリ,VRリハビリ,在宅リハビリ,ゲーミフィケーション','digital rehabilitation,VR rehabilitation,home rehabilitation,gamification'),
('inno_diff_380','自動化倉庫・物流ロボット採用研究','Automated Warehouse and Logistics Robot Adoption Research','Amazon Robotics・Goods-to-Person・自動フォークリフトなど倉庫自動化技術の採用を分析した研究群。導入コスト・天井高制約・SKU複雑性・作業員との協働設計が採用規定因として確認されている。','物流産業のDX戦略と雇用影響政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','物流ロボット採用研究','2015','meso','adoption','warehouse_automation_adoption','["Mangan, J.", "Lalwani, C.", "Butcher, T."]','["Mangan et al. (2008) Global logistics", "Boysen et al. (2019) Warehousing automation"]','倉庫自動化,物流ロボット,Amazon Robotics,自動フォークリフト','warehouse automation,logistics robot,Amazon Robotics,automated forklift'),
('inno_diff_381','土地登記デジタル化採用研究','Land Registry Digitalization Adoption Research','ブロックチェーン土地台帳・電子抵当・デジタル不動産登記への法務機関・不動産業者採用を分析した研究群。法制度改革・権利侵害リスク・デジタルリテラシー・紙媒体との並行運用コストが採用規定因として確認されている。','土地行政改革と不動産デジタル化政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','不動産テック採用研究','2017','meso','adoption','legal_system_adoption','["Vos, J.", "van den Berg, C.", "Lemmen, C."]','["Vos et al. (2017) Blockchain land registry", "Lemmen (2012) Land administration"]','土地登記,ブロックチェーン台帳,不動産デジタル化,電子抵当','land registry,blockchain ledger,real estate digitalization,e-mortgage'),
('inno_diff_382','スマート廃棄物管理採用研究','Smart Waste Management Adoption Research','IoTセンサー内蔵ゴミ箱・AIルート最適化・廃棄物分別認識AIへの自治体採用を分析した研究群。初期投資・市民行動変容との統合・データプライバシー・維持管理コストが採用規定因として確認されている。','スマートシティ廃棄物政策と循環経済インフラ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマート廃棄物採用研究','2016','meso','adoption','municipal_smart_adoption','["Hannan, M.A.", "Hasan, M.M.", "Rashid, M.M."]','["Hannan et al. (2015) Solid waste management IoT", "Hasan et al. (2020) Smart waste management"]','スマート廃棄物,IoTゴミ箱,廃棄物分別AI,スマートシティ廃棄物','smart waste,IoT bin,waste sorting AI,smart city waste'),
('inno_diff_383','デジタル・ツイン都市政策採用研究','Digital Twin City Policy Adoption Research','国家・都市デジタルツイン政策（英国National Digital Twin等）の政策立案者採用を分析した研究群。政府間調整コスト・ベンダー依存・市民データ所有権・政策正当性が採用規定因として確認されている。','デジタル国土管理政策と官民データ連携設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','政策デジタルツイン採用研究','2019','macro','adoption','policy_digital_adoption','["Bolton, A.", "Butler, L.", "Dabson, I."]','["Bolton et al. (2018) Gemini Principles", "Dabson et al. (2022) Digital twin policy review"]','デジタルツイン都市政策,国家デジタルツイン,政府DX,データ主権','digital twin city policy,national digital twin,government DX,data sovereignty'),
('inno_diff_384','インダストリー4.0採用のサプライチェーン研究','Supply Chain Research on Industry 4.0 Adoption','CPS・IoT・AIを統合したインダストリー4.0技術のサプライチェーン採用を分析した研究群。技術統合複雑性・サプライヤーのデジタル成熟度格差・標準化不足・リスク分担が採用規定因として確認されている。','製造サプライチェーンのデジタル化政策と産業補助金設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','インダストリー4.0採用研究','2018','meso','adoption','industry40_supply_chain','["Tortorella, G.L.", "Fettermann, D.", "Frank, A.G."]','["Tortorella & Fettermann (2018) I4.0 lean production", "Frank et al. (2019) Industry 4.0 technologies"]','インダストリー4.0,サプライチェーンDX,CPS,製造デジタル化','Industry 4.0,supply chain DX,CPS,manufacturing digitalization'),
('inno_diff_385','デジタル通貨決済採用の小売業者研究','Retailer Research on Digital Currency Payment Adoption','ビットコイン・USDC・CBDCを店頭決済手段として採用する小売業者の意思決定を分析した研究群。価格変動リスク・決済手数料・顧客需要・会計・税務処理の複雑さが採用規定因として確認されている。','小売業のデジタル決済戦略とCBDC普及政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル通貨小売採用研究','2020','meso','adoption','merchant_crypto_adoption','["Pieters, G.", "Vivanco, S.", "Chiu, J."]','["Pieters & Vivanco (2017) Bitcoin price", "Chiu & Koeppl (2022) CBDC design"]','デジタル通貨,CBDC,小売業者採用,暗号資産決済','digital currency,CBDC,retailer adoption,crypto payment'),
('inno_diff_386','スマートファクトリー採用の中小製造業研究','SME Manufacturing Research on Smart Factory Adoption','中小製造業によるスマートファクトリー化（IoT・クラウドMES・AI品質管理）の採用を分析した研究群。初期投資不安・IT人材不足・ROI可視化・大企業サプライヤーへの圧力が採用規定因として確認されている。','中小製造業の競争力強化政策とサプライチェーンデジタル化支援に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマートファクトリー採用研究','2019','meso','adoption','sme_manufacturing_adoption','["Müller, J.M.", "Buliga, O.", "Voigt, K.I."]','["Müller et al. (2018) SME digitalization", "Buliga et al. (2016) Business model innovation"]','スマートファクトリー,中小製造業,IoT製造,MES','smart factory,SME manufacturing,IoT manufacturing,MES'),
('inno_diff_387','エドテック採用のK-12教育研究','K-12 Education Research on EdTech Adoption','小中高等学校でのタブレット・学習管理システム・AIチュータリングツール採用を分析した研究群。学校管理者の支持・教師研修・保護者の関与・BYOD政策が採用規定因として確認されている。1人1台政策（GIGAスクール等）の効果研究も含まれる。','教育ICT政策と学校のデジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','K-12 EdTech採用研究','2012','meso','adoption','school_digital_adoption','["Tondeur, J.", "van Braak, J.", "Sipilä, K."]','["Tondeur et al. (2008) Primary school ICT integration", "Sipilä (2014) ICT integration obstacles"]','K-12 EdTech,学習管理システム,タブレット採用,GIGAスクール','K-12 EdTech,learning management system,tablet adoption,GIGA school'),
('inno_diff_388','高齢者向けソーシャルロボット採用の認知症ケア研究','Dementia Care Research on Social Robot Adoption for Elderly','PARO・iRobot・Stevie等ソーシャルロボットの認知症ケアへの採用を分析した研究群。認知症の行動・心理症状（BPSD）緩和効果・介護負担軽減・倫理的欺瞞懸念が採用規定因として確認されている。','認知症ケア政策とソーシャルロボティクス倫理規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','認知症ケアロボット採用研究','2016','meso','adoption','dementia_care_adoption','["Wada, K.", "Shibata, T.", "Morita, T."]','["Wada & Shibata (2007) PARO emotional robot", "Morita et al. (2011) PARO dementia"]','PARO,認知症ケアロボット,BPSD,介護ロボット倫理','PARO,dementia care robot,BPSD,care robot ethics'),
('inno_diff_389','プロフェッショナルSNS採用研究（LinkedIn等）','Professional Social Network Adoption Research','LinkedIn・Xing・Indeed・Wantedlyなどプロフェッショナルソーシャルネットワークへの個人採用を分析した研究群。キャリア資本形成動機・採用者との接続期待・インターフォーマルな知識共有が採用規定因として確認されている。','HRテックのソーシャルリクルーティング戦略と個人のキャリア開発戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','プロフェッショナルSNS採用研究','2010','micro','adoption','career_networking_adoption','["Skeels, M.M.", "Grudin, J.", "Zheng, W."]','["Skeels & Grudin (2009) When enterprise met SNS", "Zheng et al. (2011) LinkedIn adoption"]','プロフェッショナルSNS,LinkedIn,ソーシャルリクルーティング,キャリア資本','professional SNS,LinkedIn,social recruiting,career capital'),
('inno_diff_390','サイバーフィジカルシステム採用の製造研究','Manufacturing Research on Cyber-Physical System Adoption','CPS（サイバーフィジカルシステム）の製造業採用を分析した研究群。リアルタイムデータ統合・セキュリティ脆弱性・レガシー設備との互換性・人-機械インタラクション設計が採用規定因として確認されている。','製造業のデジタル変革政策とCPS国際標準化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','CPS採用研究','2015','meso','adoption','cps_manufacturing_adoption','["Lee, J.", "Bagheri, B.", "Kao, H.A."]','["Lee et al. (2015) CPS Industry 4.0", "Bagheri et al. (2015) Cyber-Physical manufacturing"]','CPS,サイバーフィジカル,製造DX,レガシー互換','CPS,cyber-physical systems,manufacturing DX,legacy compatibility'),
('inno_diff_391','分散型再生可能エネルギー採用の農村研究','Rural Research on Distributed Renewable Energy Adoption','農村コミュニティへのミニグリッド・オフグリッド太陽光・バイオガス等分散型再エネ採用を分析した研究群。グリッド拡張コスト比較・コミュニティ所有モデル・ファイナンスアクセス・技術サポートが採用規定因として確認されている。','途上国農村電化政策と分散型エネルギーシステム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農村再エネ採用研究','2013','meso','adoption','rural_energy_adoption','["Bhattacharyya, S.C.", "Palit, D.", "Ulsrud, K."]','["Bhattacharyya & Palit (2014) Mini-grid electrification", "Ulsrud et al. (2015) Solar community"]','農村電化,ミニグリッド,分散型再エネ,オフグリッド','rural electrification,mini-grid,distributed renewable energy,off-grid'),
('inno_diff_392','医薬品アドヒアランス向上技術採用研究','Technology Adoption for Medication Adherence Improvement','スマートピルボトル・服薬リマインダーアプリ・薬局自動調剤サービスへの患者採用を分析した研究群。忘れやすさ・副作用への恐れ・ルーティン統合困難・コストが採用規定因として確認されている。慢性疾患管理への応用が特に重要とされている。','薬物療法コンプライアンス政策と薬局デジタル変革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','服薬アドヒアランス採用研究','2015','micro','adoption','adherence_support_adoption','["Cramer, J.A.", "Roy, A.", "Tarn, D.M."]','["Cramer et al. (2008) Medication compliance", "Tarn et al. (2017) Medication adherence tech"]','服薬アドヒアランス,スマートピルボトル,服薬リマインダー,慢性疾患','medication adherence,smart pill bottle,medication reminder,chronic disease'),
('inno_diff_393','コレクティブインテリジェンスプラットフォーム採用研究','Collective Intelligence Platform Adoption Research','IdeaScale・Loomio・Pol.is等集合知プラットフォームへの組織・コミュニティ採用を分析した研究群。参加動機・意思決定権限委譲・アルゴリズムによる意見集約への信頼・ガバナンス設計が採用規定因として確認されている。','民主的イノベーション政策と組織意思決定システム改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','集合知プラットフォーム採用研究','2014','meso','adoption','collective_intelligence_adoption','["Malone, T.W.", "Woolley, A.W.", "Lévy, P."]','["Malone et al. (2010) Collective intelligence", "Woolley et al. (2010) Evidence for collective intelligence"]','集合知,コレクティブインテリジェンス,民主的イノベーション,参加型意思決定','collective intelligence,participatory decision-making,democratic innovation,crowdwisdom'),
('inno_diff_394','ダークパターンと採用操作研究','Dark Patterns and Adoption Manipulation Research','チェックボックスの事前チェック・目立たない解約ボタン・偽の緊急性表示等ダークパターンがシステム採用統計を歪める構造を分析した研究群。消費者保護規制（DSA・CPA）によるダークパターン規制の効果研究も含まれる。','消費者保護政策とUI倫理設計の標準化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ダークパターン採用研究','2016','micro','adoption','dark_pattern_manipulation','["Brignull, H.", "Gray, C.M.", "Bösch, C."]','["Brignull (2010) Dark patterns", "Gray et al. (2018) Dark patterns at scale"]','ダークパターン,UI操作,消費者保護,採用統計歪曲','dark patterns,UI manipulation,consumer protection,adoption statistics distortion'),
('inno_diff_395','デジタルツールの包摂的採用研究（障害者）','Inclusive Adoption Research of Digital Tools for People with Disabilities','視覚障害者のスクリーンリーダー・聴覚障害者の字幕AI・肢体不自由者のスイッチアクセス等支援技術とデジタルツールへの障害者採用を分析した研究群。アクセシビリティ設計品質・制度的支援・社会的スティグマが採用規定因として確認されている。','障害者権利条約（CRPD）の実施とデジタルアクセシビリティ政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','包摂的採用・アクセシビリティ研究','2008','micro','adoption','accessibility_adoption','["Goggin, G.", "Newell, C.", "Shinohara, K."]','["Goggin & Newell (2003) Digital Disability", "Shinohara & Wobbrock (2011) AT design"]','デジタルアクセシビリティ,支援技術,障害者採用,スクリーンリーダー','digital accessibility,assistive technology,disability adoption,screen reader'),
('inno_diff_396','アグリビジネスの垂直統合技術採用研究','Agribusiness Vertical Integration Technology Adoption Research','大手食品企業・農業コーポレートによる農場管理システム・予測農業・農産物トレーサビリティの垂直統合型採用を分析した研究群。農家との権力関係・データ支配・サプライチェーン効率化が採用規定因として確認されている。','食料サプライチェーン政策と農業デジタル化のガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','アグリビジネス採用研究','2017','macro','adoption','vertical_integration_adoption','["Howard, P.H.", "Hendrickson, M.K.", "Welsh, R."]','["Howard (2016) Concentration in Agrifood", "Hendrickson & Heffernan (2002) Concentration in agricultural markets"]','アグリビジネス,垂直統合,農産物トレーサビリティ,データ農業支配','agribusiness,vertical integration,agricultural traceability,digital agriculture dominance'),
('inno_diff_397','次世代通信（5G）採用の産業・消費者研究','Industrial and Consumer Research on 5G Adoption','5G通信への産業（製造・医療・物流）と消費者採用の規定因を分析した研究群。帯域幅要求・コストプレミアム・セキュリティ懸念（ファーウェイ問題含む）・キラーユースケースの不明確さが採用規定因として確認されている。','5Gインフラ政策と通信産業の競争政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','5G採用研究','2020','meso','adoption','next_gen_network_adoption','["Ranaweera, C.", "Jurcut, A.D.", "Liyanage, M."]','["Ranaweera et al. (2021) 5G network adoption", "Liyanage et al. (2021) 5G security"]','5G採用,次世代通信,産業5G,帯域幅','5G adoption,next-generation network,industrial 5G,bandwidth'),
('inno_diff_398','フードサービスロボット採用研究（調理・サービスロボット）','Food Service Robot Adoption Research: Cooking and Service Robots','Miso Robotics・Bear Robotics等調理ロボット・運搬ロボットのファストフード・レストランチェーン採用を分析した研究群。食品安全規制・調理速度・清掃容易性・顧客受容・労働コスト削減動機が採用規定因として確認されている。','フードサービス産業のDX戦略と食品安全規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','フードサービスロボット採用研究','2019','meso','adoption','food_service_automation','["Ivanov, S.", "Seyitoğlu, F.", "Markova, M."]','["Ivanov et al. (2020) Robots in food service", "Seyitoğlu & Ivanov (2020) Restaurant robot acceptance"]','調理ロボット,フードサービスロボット,ファストフードDX,食品安全','cooking robot,food service robot,fast food DX,food safety'),
('inno_diff_399','プレシジョンメディシン採用の患者研究','Patient Research on Precision Medicine Adoption','ゲノム解析・液体生検・マルチオミクスを用いたがん精密医療への患者採用と参加意欲を分析した研究群。情報理解度・リスク開示受容・差別懸念（保険・雇用）・治療期待が採用規定因として確認されている。','精密医療保険適用政策と患者インフォームドコンセント設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','精密医療採用研究','2018','micro','adoption','precision_medicine_adoption','["Vassy, J.L.", "McLaughlin, H.M.", "Christensen, K.D."]','["Vassy et al. (2017) Patients and precision medicine", "Christensen et al. (2016) Genomic medicine patient"]','精密医療,ゲノム解析,液体生検,マルチオミクス','precision medicine,genome analysis,liquid biopsy,multi-omics'),
('inno_diff_400','コンピュテーショナルソーシャルサイエンス採用の研究者研究','Researcher Adoption of Computational Social Science Methods','大規模SNSデータ・自然言語処理・機械学習を用いた計算社会科学の社会科学研究者採用を分析した研究群。計算スキルの習得コスト・プライバシー倫理・再現可能性問題・伝統的方法論との補完関係が採用規定因として確認されている。','社会科学の方法論的転換と研究倫理審査制度改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','計算社会科学採用研究','2014','micro','adoption','computational_method_adoption','["Lazer, D.", "Pentland, A.", "Salganik, M.J."]','["Lazer et al. (2009) Computational social science", "Salganik (2017) Bit by Bit"]','計算社会科学,SNSデータ,機械学習社会科学,計算スキル','computational social science,social media data,machine learning social science,computational skills');
